#requires -Version 5.1
[CmdletBinding()]
param(
  [string]$ProjectPath = 'C:\Users\hramirez\Documents\PROYECTOS-H\ZelogiG',
  [switch]$Commit,
  [switch]$Push
)
Set-StrictMode -Version Latest
$ErrorActionPreference = 'Stop'

function Write-Encoded([string]$RelativePath, [string]$Payload) {
  $target = Join-Path $ProjectPath $RelativePath
  $parent = Split-Path -Parent $target
  if (-not (Test-Path -LiteralPath $parent)) { New-Item -ItemType Directory -Path $parent -Force | Out-Null }
  if (Test-Path -LiteralPath $target) {
    $stamp = Get-Date -Format 'yyyyMMdd-HHmmss'
    Copy-Item -LiteralPath $target -Destination "$target.backup-$stamp" -Force
  }
  [IO.File]::WriteAllBytes($target, [Convert]::FromBase64String($Payload))
  Write-Host "ACTUALIZADO: $RelativePath" -ForegroundColor Green
}

Write-Host 'ZelogiG - Elevación técnica y creativa' -ForegroundColor Cyan
Write-Host 'Se registrará la tarea en la bitácora.' -ForegroundColor Yellow

Write-Encoded 'docs\26_engine_architecture.md' ''
Write-Encoded 'docs\27_art_direction.md' ''
Write-Encoded 'docs\28_ai_asset_workflow.md' ''
Write-Encoded 'docs\29_development_environment.md' ''
Write-Encoded 'docs\30_level_creation_pipeline.md' ''
Write-Encoded 'docs\31_quality_gates.md' ''
Write-Encoded 'docs\32_decision_backlog.md' ''
Write-Encoded 'docs\33_ai_handoff.md' ''
Write-Encoded 'docs\34_product_identity.md' ''
Write-Encoded 'docs\decisions\DECISION-TEMPLATE.md' ''
Write-Encoded 'docs\art\ASSET_LICENSES.md' ''
Write-Encoded 'docs\art\PROMPT_LIBRARY.md' ''
Write-Encoded 'scripts\Project-Context.ps1' ''

# Reforzar identidad sin reescribir documentos históricos.
$readme = Join-Path $ProjectPath 'README.md'
if (Test-Path $readme) {
  $text = [IO.File]::ReadAllText($readme, [Text.Encoding]::UTF8)
  if ($text -notmatch 'videojuego 2D de rompecabezas lingüísticos') {
    $identity = "`r`n## Identidad oficial`r`n`r`nZelogiG es un videojuego 2D de rompecabezas lingüísticos donde las palabras reescriben el mundo.`r`n"
    [IO.File]::WriteAllText($readme, $text + $identity, (New-Object Text.UTF8Encoding($false)))
  }
}

# Agregar entrada sin depender del helper.
$logPath = Join-Path $ProjectPath 'docs\bitacora.md'
if (Test-Path $logPath) {
  $content = [IO.File]::ReadAllText($logPath, [Text.Encoding]::UTF8)
  if ($content -notmatch 'Elevación técnica, creativa y operativa') {
    $entry = @"
## $(Get-Date -Format 'yyyy-MM-dd') - Elevación técnica, creativa y operativa

- **Estado:** COMPLETO
- **Que se hizo:** Se definieron arquitectura funcional del motor, aplicación práctica de SOLID, dirección artística, flujo de recursos con IA, entorno local, laboratorio, proceso de niveles, puertas de calidad, decisiones pendientes y protocolo de entrega a otras IA.
- **Decision + porque:** [Seguro] ZelogiG se consolida como videojuego 2D de rompecabezas lingüísticos. El motor seguirá siendo local, determinista y desacoplado; CSS y SVG serán la base visual del MVP; las decisiones estructurales se presentarán al propietario antes de modificar código.
- **Contexto:** Lectura directa de la documentación del proyecto y decisiones del propietario; graphify no disponible y no generado.
- **Validacion:** Archivos generados con PowerShell 5.1. Validaciones de Node.js pendientes por bloqueo corporativo.
- **Costo:** No disponible desde este entorno; no se inventan tokens ni USD.
- **Siguiente paso:** Publicar la documentación, instalar Node.js en un equipo autorizado y ejecutar validación de tipos, pruebas y servidor local.
- **Bloqueos / pendientes de humano:** Node.js no disponible en el equipo corporativo. Autenticación de GitHub debe usar la cuenta propietaria del repositorio.

### Decisiones deliberadas, no deshacer

- ZelogiG es un juego, no un simulador profesional.
- Motor funcional y determinista.
- CSS y SVG para el MVP; IA para conceptos bajo revisión humana.
- Cinco niveles manuales antes de crear un editor.
- Toda decisión estructural se presenta antes de modificar código.

---

"@
    $marker = '---'
    $index = $content.IndexOf($marker)
    if ($index -ge 0) {
      $insertAt = $index + $marker.Length
      $updated = $content.Substring(0,$insertAt) + "`r`n`r`n" + $entry + $content.Substring($insertAt).TrimStart("`r","`n")
      [IO.File]::WriteAllText($logPath, $updated, (New-Object Text.UTF8Encoding($false)))
      Write-Host 'ACTUALIZADO: docs\bitacora.md' -ForegroundColor Green
    }
  }
}

$audit = Join-Path $ProjectPath 'scripts\Audit-ZelogiG.ps1'
if (Test-Path $audit) { & $audit }

if ($Commit -or $Push) {
  Push-Location $ProjectPath
  try {
    git add .
    $pending = git status --porcelain
    if ($pending) { git commit -m 'docs: elevate ZelogiG architecture and production standards' }
    else { Write-Host 'Git: no hay cambios para commit.' -ForegroundColor Yellow }
    if ($Push) { git push -u origin main }
  }
  finally { Pop-Location }
}

Write-Host ''
Write-Host 'Elevación completada.' -ForegroundColor Cyan
Write-Host 'Sin -Commit solo se modifican archivos. Con -Commit se crea commit. Con -Push también intenta publicar.' -ForegroundColor White
